// Extract political markets with yes/no prices as implied probabilities
const markets = $input.all();
const politicalMarkets = [];

for (const item of markets) {
  const m = item.json;
  const question = m.question || m.title || '';
  const outcomes = typeof m.outcomes === 'string' ? JSON.parse(m.outcomes) : (m.outcomes || []);
  const prices = typeof m.outcomePrices === 'string' ? JSON.parse(m.outcomePrices) : (m.outcomePrices || []);

  // Build outcome map
  const outcomeData = [];
  for (let i = 0; i < outcomes.length; i++) {
    const name = outcomes[i];
    const price = Number(prices[i] || 0);
    outcomeData.push({
      name,
      price,
      impliedProbability: (price * 100).toFixed(1)
    });
  }

  // Extract candidate/party names from question and outcomes
  // Common patterns: "Will X win the election?", "X to win?", "Next president: X?"
  politicalMarkets.push({
    json: {
      question,
      conditionId: m.conditionId || '',
      slug: m.slug || '',
      outcomes: outcomeData,
      // Store the primary candidate/outcome and its probability
      primaryOutcome: outcomeData[0]?.name || 'Yes',
      marketProbability: Number(outcomeData[0]?.impliedProbability || 0)
    }
  });
}

return politicalMarkets;

// Compare Polymarket implied probability vs polling averages
// Flag divergences above threshold
const DIVERGENCE_THRESHOLD = 10; // Alert if difference > 10 percentage points

const polymarketData = $('Extract Political Markets').all();
const pollingResponse = $input.all();

// Parse polling data -- adjust this section based on your data source format
// Expected: array of { race, candidate, pollAverage } or similar
let polls = [];
try {
  const raw = pollingResponse[0]?.json;
  if (Array.isArray(raw)) {
    polls = raw;
  } else if (raw?.races) {
    polls = raw.races;
  } else if (raw?.data) {
    polls = raw.data;
  }
} catch (e) {
  // If parsing fails, return empty
  return [{ json: { _skip: true, error: 'Could not parse polling data' } }];
}

// Build polling lookup by candidate/race name
const pollingLookup = {};
for (const poll of polls) {
  const candidate = (poll.candidate || poll.name || poll.answer || '').toLowerCase();
  const race = (poll.race || poll.question || poll.state || '').toLowerCase();
  const avg = Number(poll.pollAverage || poll.pct || poll.value || poll.percentage || 0);

  if (candidate && avg > 0) {
    pollingLookup[candidate] = { race, pollAvg: avg };
  }
  // Also index by race + candidate
  if (race && candidate) {
    pollingLookup[`${race}_${candidate}`] = { race, pollAvg: avg };
  }
}

const divergences = [];

for (const pm of polymarketData) {
  const question = (pm.json.question || '').toLowerCase();
  const outcomes = pm.json.outcomes || [];

  for (const outcome of outcomes) {
    const outcomeName = (outcome.name || '').toLowerCase();
    const marketProb = Number(outcome.impliedProbability || 0);

    // Try to find matching polling data
    let pollAvg = null;
    let matchKey = null;

    // Direct name match
    if (pollingLookup[outcomeName]) {
      pollAvg = pollingLookup[outcomeName].pollAvg;
      matchKey = outcomeName;
    }

    // Partial match
    if (!pollAvg) {
      for (const key in pollingLookup) {
        if (outcomeName.includes(key) || key.includes(outcomeName) ||
            question.includes(key)) {
          pollAvg = pollingLookup[key].pollAvg;
          matchKey = key;
          break;
        }
      }
    }

    if (pollAvg !== null) {
      const diff = Math.abs(marketProb - pollAvg);

      if (diff >= DIVERGENCE_THRESHOLD) {
        const direction = marketProb > pollAvg
          ? 'Market MORE confident than polls'
          : 'Market LESS confident than polls';

        divergences.push({
          json: {
            race: pm.json.question,
            outcome: outcome.name,
            pollAvg: pollAvg.toFixed(1) + '%',
            marketPrice: marketProb.toFixed(1) + '%',
            gap: diff.toFixed(1) + '%',
            direction,
            alertMessage: `Divergence Alert: ${pm.json.question}\n${outcome.name}: Polls ${pollAvg.toFixed(1)}% vs Market ${marketProb.toFixed(1)}%\nGap: ${diff.toFixed(1)}% -- ${direction}`
          }
        });
      }
    }
  }
}

if (divergences.length === 0) {
  return [{ json: { _skip: true } }];
}

return divergences;
